# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handleUniversalLink(_ url: URL, completion: @escaping (Bool) -> Void) {
        guard url.host == "myapp.com" else {
            completion(false)
            return
        }
        
        let components = URLComponents(url: url, resolvingAgainstBaseURL: true)
        
        if let path = components?.path, path == "/reset-password" {
            if let token = components?.queryItems?.first(where: { $0.name == "token" })?.value {
                navigateToPasswordResetScreen(token: token)
                completion(true)
            } else {
                completion(false)
            }
        } else {
            completion(false)
        }
    }
    
    private func navigateToPasswordResetScreen(token: String) {
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first else { return }
            
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            if let passwordResetVC = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController {
                passwordResetVC.resetToken = token
                window.rootViewController?.present(passwordResetVC, animated: true)
            }
        }
    }
}

extension AppDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            UniversalLinkHandler.shared.handleUniversalLink(url) { success in
                if success {
                    restorationHandler([])
                }
            }
            return true
        }
        return false
    }
}

extension SceneDelegate {
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            UniversalLinkHandler.shared.handleUniversalLink(url) { _ in }
        }
    }
}